// Transformar materiales: aplanar array y calcular total_cop
const body = $input.first().json.body;

const fecha = body.fecha;
const proyecto = body.proyecto;
const reportado_por = body.reportado_por || 'Desconocido';
const timestamp_sync = new Date().toISOString();

if (!Array.isArray(body.materiales) || body.materiales.length === 0) {
  throw new Error('El campo materiales esta ausente o vacio');
}

const rows = body.materiales.map((mat, idx) => {
  const nombre = mat.nombre;
  const cantidad = Number(mat.cantidad);
  const unidad = mat.unidad;
  const costo_unitario = Number(mat.costo_unitario);

  if (!nombre || isNaN(cantidad) || !unidad || isNaN(costo_unitario)) {
    throw new Error(`Material en indice ${idx} tiene campos invalidos: ${JSON.stringify(mat)}`);
  }

  const total_cop = cantidad * costo_unitario;

  return {
    json: {
      fecha,
      proyecto,
      nombre,
      cantidad,
      unidad,
      costo_unitario,
      total_cop,
      reportado_por,
      timestamp_sync
    }
  };
});

return rows;

// Construir respuesta estructurada de exito
const allItems = $input.all();
const records_processed = allItems.length;
const timestamp = new Date().toISOString();

return [
  {
    json: {
      status: 'ok',
      records_processed,
      timestamp
    }
  }
];

// Payload invalido — construir respuesta de error 400
const timestamp = new Date().toISOString();

return [
  {
    json: {
      status: 'error',
      message: 'Payload invalido. Se requieren: fecha (string), proyecto (string), materiales (array no vacio).',
      timestamp
    }
  }
];

// Formatear alerta de error segun estandar Keystone
const error = $input.first().json;

const workflowName = error.workflow?.name || 'Inventario-Barbosa';
const nodeName = error.execution?.lastNodeExecuted || 'Desconocido';
const message = error.execution?.error?.message || 'Sin mensaje de error';
const timestamp = new Date().toISOString();

const alertMessage = `[n8n ERROR] Workflow: ${workflowName} | Node: ${nodeName} | Message: ${message} | Time: ${timestamp}`;

return [
  {
    json: {
      alert: alertMessage,
      workflow: workflowName,
      node: nodeName,
      message,
      timestamp,
      to: 'thomasreyesr@gmail.com',
      subject: `[n8n ERROR] Inventario-Barbosa — ${nodeName}`
    }
  }
];
